import requests

def make_proxied_request(url: str, proxy: str, method: str = 'GET', **kwargs):
    proxies = {
        "http": proxy,
        "https": proxy,
    }
    try:
        response = requests.request(method, url, proxies=proxies, **kwargs)
        response.raise_for_status()
        return response
    except requests.exceptions.RequestException:
        return None
